     1→package transflow
     2→
     3→import (
     4→	"context"
     5→	"fmt"
     6→	"path"
     7→	"time"
     8→
     9→	consulapi "github.com/hashicorp/consul/api"
    10→	"github.com/iw2rmb/ploy/internal/orchestration"
    11→)
    12→
    13→// Lock represents an acquired lock with metadata
    14→type Lock struct {
    15→	Key       string
    16→	SessionID string
    17→	TTL       time.Duration
    18→	client    *consulapi.Client
    19→}
    20→
    21→// KBLockManager provides distributed locking for KB operations
    22→type KBLockManager interface {
    23→	AcquireLock(ctx context.Context, key string, ttl time.Duration) (*Lock, error)
    24→	ReleaseLock(ctx context.Context, lock *Lock) error
    25→	IsLocked(ctx context.Context, key string) (bool, error)
    26→	TryWithLockRetry(ctx context.Context, key string, config *LockConfig, fn func() error) error
    27→}
    28→
    29→// ConsulKBLockManager implements KBLockManager using Consul KV
    30→type ConsulKBLockManager struct {
    31→	client *consulapi.Client
    32→	kv     orchestration.KV
    33→}
    34→
    35→// NewConsulKBLockManager creates a new Consul-based lock manager
    36→func NewConsulKBLockManager(kv orchestration.KV) *ConsulKBLockManager {
    37→	// Get the consul client from the KV interface
    38→	// We need to create our own client for session management
    39→	cfg := consulapi.DefaultConfig()
    40→	client, _ := consulapi.NewClient(cfg)
    41→
    42→	return &ConsulKBLockManager{
    43→		client: client,
    44→		kv:     kv,
    45→	}
    46→}
    47→
    48→// AcquireLock attempts to acquire a distributed lock with TTL
    49→func (m *ConsulKBLockManager) AcquireLock(ctx context.Context, key string, ttl time.Duration) (*Lock, error) {
    50→	// Create a session for the lock
    51→	sessionOpts := &consulapi.SessionEntry{
    52→		Name:      fmt.Sprintf("kb-lock-%s", key),
    53→		TTL:       ttl.String(),
    54→		Behavior:  consulapi.SessionBehaviorDelete,
    55→		LockDelay: 1 * time.Second,
    56→	}
    57→
    58→	sessionID, _, err := m.client.Session().Create(sessionOpts, nil)
    59→	if err != nil {
    60→		return nil, fmt.Errorf("failed to create session: %w", err)
    61→	}
    62→
    63→	lockKey := m.buildLockKey(key)
    64→
    65→	// Attempt to acquire the lock
    66→	kvPair := &consulapi.KVPair{
    67→		Key:     lockKey,
    68→		Value:   []byte(sessionID),
    69→		Session: sessionID,
    70→	}
    71→
    72→	acquired, _, err := m.client.KV().Acquire(kvPair, nil)
    73→	if err != nil {
    74→		// Clean up session if lock acquisition failed
    75→		m.client.Session().Destroy(sessionID, nil)
    76→		return nil, fmt.Errorf("failed to acquire lock: %w", err)
    77→	}
    78→
    79→	if !acquired {
    80→		// Clean up session if lock was not acquired
    81→		m.client.Session().Destroy(sessionID, nil)
    82→		return nil, fmt.Errorf("lock already held by another session")
    83→	}
    84→
    85→	return &Lock{
    86→		Key:       lockKey,
    87→		SessionID: sessionID,
    88→		TTL:       ttl,
    89→		client:    m.client,
    90→	}, nil
    91→}
    92→
    93→// ReleaseLock releases a previously acquired lock
    94→func (m *ConsulKBLockManager) ReleaseLock(ctx context.Context, lock *Lock) error {
    95→	if lock == nil {
    96→		return fmt.Errorf("cannot release nil lock")
    97→	}
    98→
    99→	// Release the lock by destroying the session
   100→	_, err := m.client.Session().Destroy(lock.SessionID, nil)
   101→	if err != nil {
   102→		return fmt.Errorf("failed to destroy lock session: %w", err)
   103→	}
   104→
   105→	return nil
   106→}
   107→
   108→// IsLocked checks if a key is currently locked
   109→func (m *ConsulKBLockManager) IsLocked(ctx context.Context, key string) (bool, error) {
   110→	lockKey := m.buildLockKey(key)
   111→
   112→	kvPair, _, err := m.client.KV().Get(lockKey, nil)
   113→	if err != nil {
   114→		return false, fmt.Errorf("failed to check lock status: %w", err)
   115→	}
   116→
   117→	return kvPair != nil && kvPair.Session != "", nil
   118→}
   119→
   120→// buildLockKey builds the full Consul KV key for a lock
   121→func (m *ConsulKBLockManager) buildLockKey(key string) string {
   122→	return path.Join("kb/locks", key)
   123→}
   124→
   125→// TryWithLock attempts to acquire a lock and execute a function with it
   126→// This is a convenience method for common lock-execute-unlock patterns
   127→func (m *ConsulKBLockManager) TryWithLock(ctx context.Context, key string, ttl time.Duration, fn func() error) error {
   128→	lock, err := m.AcquireLock(ctx, key, ttl)
   129→	if err != nil {
   130→		return fmt.Errorf("failed to acquire lock: %w", err)
   131→	}
   132→	defer m.ReleaseLock(ctx, lock)
   133→
   134→	return fn()
   135→}
   136→
   137→// BuildSignatureLockKey builds a lock key for an error signature
   138→func BuildSignatureLockKey(lang, signature string) string {
   139→	return path.Join(lang, signature)
   140→}
   141→
   142→// AcquireSignatureLock is a convenience method for locking error signature operations
   143→func (m *ConsulKBLockManager) AcquireSignatureLock(ctx context.Context, lang, signature string, ttl time.Duration) (*Lock, error) {
   144→	key := BuildSignatureLockKey(lang, signature)
   145→	return m.AcquireLock(ctx, key, ttl)
   146→}
   147→
   148→// LockConfig contains configuration for lock operations
   149→type LockConfig struct {
   150→	DefaultTTL    time.Duration
   151→	MaxWaitTime   time.Duration
   152→	RetryInterval time.Duration
   153→	MaxRetries    int
   154→}
   155→
   156→// DefaultLockConfig returns reasonable defaults for KB operations
   157→func DefaultLockConfig() *LockConfig {
   158→	return &LockConfig{
   159→		DefaultTTL:    5 * time.Second,
   160→		MaxWaitTime:   10 * time.Second,
   161→		RetryInterval: 100 * time.Millisecond,
   162→		MaxRetries:    3,
   163→	}
   164→}
   165→
   166→// TryWithLockRetry attempts to acquire a lock with retries
   167→func (m *ConsulKBLockManager) TryWithLockRetry(ctx context.Context, key string, config *LockConfig, fn func() error) error {
   168→	if config == nil {
   169→		config = DefaultLockConfig()
   170→	}
   171→
   172→	var lastErr error
   173→	for attempt := 0; attempt < config.MaxRetries; attempt++ {
   174→		lock, err := m.AcquireLock(ctx, key, config.DefaultTTL)
   175→		if err != nil {
   176→			lastErr = err
   177→			// Wait before retrying
   178→			select {
   179→			case <-ctx.Done():
   180→				return ctx.Err()
   181→			case <-time.After(config.RetryInterval):
   182→				continue
   183→			}
   184→		}
   185→
   186→		// Execute function with lock held
   187→		err = fn()
   188→		releaseErr := m.ReleaseLock(ctx, lock)
   189→		if releaseErr != nil {
   190→			// Log warning but don't fail the operation
   191→			// The lock will expire anyway due to TTL
   192→		}
   193→
   194→		if err == nil {
   195→			return nil // Success
   196→		}
   197→
   198→		lastErr = err
   199→	}
   200→
   201→	return fmt.Errorf("failed after %d attempts, last error: %w", config.MaxRetries, lastErr)
   202→}
